   237→   * credit curves. 
   238→   * 
   239→   * @return the CDS product
   240→   */
   241→  public ResolvedCds toSingleNameCds() {
   242→    return ResolvedCds.builder()
   243→        .buySell(getBuySell())
   244→        .dayCount(getDayCount())
   245→        .legalEntityId(getCdsIndexId())
   246→        .paymentOnDefault(getPaymentOnDefault())
   247→        .paymentPeriods(getPaymentPeriods())
   248→        .protectionEndDate(getProtectionEndDate())
   249→        .protectionStart(getProtectionStart())
   250→        .stepinDateOffset(getStepinDateOffset())
   251→        .settlementDateOffset(getSettlementDateOffset())
   252→        .build();
   253→  }
