    PeriodicSchedule paymentSchedule = product.getUnderlyingIndex().getPaymentSchedule();
    StringBuilder buf = new StringBuilder(96);
    buf.append(SummarizerUtils.datePeriod(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
    buf.append(' ');
    buf.append(product.getUnderlyingIndex().getBuySell());
    buf.append(' ');
    buf.append(SummarizerUtils.amount(product.getUnderlyingIndex().getCurrency(), product.getUnderlyingIndex().getNotional()));
    buf.append(' ');
    buf.append(String.format("TRANCHE[%.1f%%,%.1f%%]", product.getAttachmentPoint() * 100, product.getDetachmentPoint() * 100));
    buf.append(' ');
    buf.append(product.getUnderlyingIndex().getCdsIndexId().getValue());
    buf.append(" / ");
    buf.append(SummarizerUtils.percent(product.getUnderlyingIndex().getFixedRate()));
    return SummarizerUtils.summary(this, ProductType.CDS_TRANCHE, buf.toString(), product.getUnderlyingIndex().getCurrency());
  }

